def mc_get(key):
    try:
        value = memcache_client.get(key)
        if value is None:
            return None
        return json.loads(value.decode("utf-8"))
    except Exception:
        return None


def mc_set(key, value, ttl):
    try:
        memcache_client.set(key, json.dumps(value), expire=ttl)
    except Exception:
        pass


def mc_delete(key):
    try:
        memcache_client.delete(key)
    except Exception:
        pass


def make_cache_key(prefix, payload):
    raw = json.dumps(payload, sort_keys=True, separators=(",", ":"))
    digest = hashlib.sha256(raw.encode("utf-8")).hexdigest()
    return f"{prefix}:{digest}"


def cache_api_response(ttl=API_RESPONSE_TTL):
    def decorator(fn):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            payload = {
                "path": request.path,
                "method": request.method,
                "args": request.args.to_dict(flat=False),
                "kwargs": kwargs,
            }
            cache_key = make_cache_key("api", payload)
            cached = mc_get(cache_key)
            if cached is not None:
                return jsonify({"cached": True, "data": cached}), 200

            result = fn(*args, **kwargs)
            if isinstance(result, tuple):
                response_data, status_code = result
            else:
                response_data, status_code = result, 200

            if status_code == 200:
                mc_set(cache_key, response_data, ttl)

            return jsonify({"cached": False, "data": response_data}), status_code

        return wrapper

    return decorator


def get_item_from_db(item_id):
    cache_key = f"db:item:{item_id}"
    cached = mc_get(cache_key)
    if cached is not None:
        return cached, True

    conn = get_db_connection()
    cur = conn.cursor()
    cur.execute(
        "SELECT id, name, value, updated_at FROM items WHERE id = ?",
        (item_id,),
    )
    row = cur.fetchone()
    conn.close()

    if row is None:
        return None, False

    item = dict(row)
    mc_set(cache_key, item, DB_QUERY_TTL)
    return item, False


def list_items_from_db(limit=100):
    cache_key = make_cache_key("db:items", {"limit": limit})
    cached = mc_get(cache_key)
    if cached is not None:
        return cached, True

    conn = get_db_connection()
    cur = conn.cursor()
    cur.execute(
        "SELECT id, name, value, updated_at FROM items ORDER BY id LIMIT ?",
        (limit,),
    )
    rows = cur.fetchall()
    conn.close()

    items = [dict(row) for row in rows]
    mc_set(cache_key, items, DB_QUERY_TTL)
    return items, False


@app.route("/health", methods=["GET"])
def health():
    memcached_ok = True
    try:
        memcache_client.set("healthcheck", "ok", expire=5)
        memcached_ok = memcache_client.get("healthcheck") is not None
    except Exception:
        memcached_ok = False

    return jsonify(
        {
            "status": "ok",
            "memcached": memcached_ok,
        }
    )


